svg.script:

const svgNS = "http://www.w3.org/2000/svg";
const edgesGroup = document.getElementById('edges');
const nodes = [];
const nodeMap = {};
const dynamicEdges =[];
const existingLinks = new Set();
const palette =['#a4d4b4', '#e5b0c4', '#a4c8e1', '#d4a4c8', '#e5d0b0'];

// 1. Guardar y preparar los nodos para el movimiento sutil
document.querySelectorAll('.node-group').forEach(g => {
    const id = parseInt(g.getAttribute('data-id'));
    const circle = g.querySelector('circle');

    const node = {
        id: id, circle: circle,
        ix: parseFloat(circle.getAttribute('cx')),
        iy: parseFloat(circle.getAttribute('cy')),
        phaseX: Math.random() * Math.PI * 2,
        phaseY: Math.random() * Math.PI * 2,
        speedX: 0.0002 + Math.random() * 0.0003,
        speedY: 0.0002 + Math.random() * 0.0003,
        amplitudeX: 6 + Math.random() * 8, 
        amplitudeY: 6 + Math.random() * 8,
        x: 0, y: 0
    };
    nodes.push(node);
    nodeMap[id] = node;
});

// 2. Preparar los enlaces originales (nativos)
document.querySelectorAll('.edge').forEach(line => {
    const id1 = parseInt(line.getAttribute('data-n1'));
    const id2 = parseInt(line.getAttribute('data-n2'));
    const key = id1 < id2 ? id1 + '-' + id2 : id2 + '-' + id1;
    existingLinks.add(key);

    // Fijamos la opacidad de los enlaces originales
    line.setAttribute('opacity', '0.6'); 

    dynamicEdges.push({
        line: line,
        n1: nodeMap[id1],
        n2: nodeMap[id2],
        isOriginal: true
    });
});

// 3. Crear enlaces potenciales entre puntos cercanos
for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
        const nA = nodes[i];
        const nB = nodes[j];
        const key = nA.id < nB.id ? nA.id + '-' + nB.id : nB.id + '-' + nA.id;

        if (!existingLinks.has(key)) {
            const dist = Math.sqrt(Math.pow(nA.ix - nB.ix, 2) + Math.pow(nA.iy - nB.iy, 2));

            if (dist < 150) {
                const line = document.createElementNS(svgNS, 'line');
                const color = palette[Math.floor(Math.random() * palette.length)];
                line.setAttribute('stroke', color);
                line.setAttribute('stroke-width', '1.2');
                line.setAttribute('opacity', '0'); // Empiezan ocultos
                edgesGroup.appendChild(line);

                dynamicEdges.push({
                    line: line,
                    n1: nA,
                    n2: nB,
                    isOriginal: false,
                    phase: Math.random() * Math.PI * 2,
                    speed: 0.0003 + Math.random() * 0.0005
                });
            }
        }
    }
}

// 4. Bucle principal de animación
function animate(timestamp) {
    // Movimiento orgánico constante de los puntos
    nodes.forEach(n => {
        n.x = n.ix + Math.sin(timestamp * n.speedX + n.phaseX) * n.amplitudeX;
        n.y = n.iy + Math.cos(timestamp * n.speedY + n.phaseY) * n.amplitudeY;

        n.circle.setAttribute('cx', n.x);
        n.circle.setAttribute('cy', n.y);
    });

    // Actualizar líneas
    dynamicEdges.forEach(e => {
        e.line.setAttribute('x1', e.n1.x);
        e.line.setAttribute('y1', e.n1.y);
        e.line.setAttribute('x2', e.n2.x);
        e.line.setAttribute('y2', e.n2.y);

        // Aparición/Desaparición solo en enlaces nuevos
        if (!e.isOriginal) {
            let currentOpacity = -0.8 + Math.sin(timestamp * e.speed + e.phase) * 1.3;
            currentOpacity = Math.max(0, Math.min(0.7, currentOpacity));
            e.line.setAttribute('opacity', currentOpacity.toFixed(2));
        }
    });

    requestAnimationFrame(animate);
}

requestAnimationFrame(animate);
